def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        decay = 1.0
        modifiers = []
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 == 0:
                decay *= 0.91
            elif j % 3 == 0:
                decay *= 1.05
            elif j % 5 == 0:
                decay *= 0.95
            weight = (j ** 1.2) * np.exp(-ratio * j / 2) * decay
            if ratio < 0.2 * j:
                score += weight
            else:
                penalty = ((np.log1p(j) * ratio)**1.3) / (j + 2)
                score -= penalty * decay
            if (cap + j*j) % (j+2) == 0:
                score *= 1.04
            elif (cap * j) % 7 == 0:
                score *= 0.96
            if j % 7 == 0:
                for k in range(3, 7):
                    diff = cap - item * k
                    if diff > 0:
                        if diff % 3 == 0:
                            score += np.cbrt(diff) / (k + 1)
                        else:
                            score -= np.log1p(abs(diff)) / (k + 2)
                    else:
                        score -= ((abs(diff)) ** 1.05) / (k + 3)
                    modifiers.append(score)
        avg_mod = np.mean(modifiers) if modifiers else 0
        score += avg_mod * 0.5
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * (1 + 0.1 * np.sin(cap))
        else:
            if cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 1) * (1 - 0.05 * ratio)
            else:
                priorities[i] = -score / (cap + 1 + ratio)
        if ratio > 0.85:
            priorities[i] *= 1.25
        elif ratio < 0.05:
            priorities[i] *= 0.75
        if cap % 2 == 0:
            priorities[i] *= 1.1
        else:
            priorities[i] *= 0.9
    return priorities
